import React, { useState, useEffect } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, PieChart, Pie, Cell, LineChart, Line } from 'recharts';
import api from '../services/api';
import { toast } from 'react-toastify';

const Analytics = () => {
  const [analytics, setAnalytics] = useState(null);
  const [voyages, setVoyages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedVessel, setSelectedVessel] = useState('');

  useEffect(() => {
    fetchAnalyticsData();
    fetchVoyages();
  }, [selectedVessel]);

  const fetchAnalyticsData = async () => {
    try {
      const response = await api.get('/analytics/dashboard/');
      setAnalytics(response.data);
    } catch (error) {
      console.error('Failed to fetch analytics:', error);
      toast.error('Failed to load analytics data');
    }
  };

  const fetchVoyages = async () => {
    try {
      const params = selectedVessel ? `?vessel_id=${selectedVessel}` : '';
      const response = await api.get(`/analytics/voyages/${params}`);
      setVoyages(response.data.results || response.data);
    } catch (error) {
      console.error('Failed to fetch voyages:', error);
      toast.error('Failed to load voyage data');
    } finally {
      setLoading(false);
    }
  };

  const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884D8'];

  if (loading) {
    return <div className="loading">Loading analytics...</div>;
  }

  return (
    <div className="container" style={{ marginTop: '30px' }}>
      <h1>Analytics & Reports</h1>

      {/* Summary Cards */}
      {analytics && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '30px' }}>
          <div className="card" style={{ textAlign: 'center' }}>
            <h3 style={{ color: '#007bff' }}>{analytics.summary.total_voyages}</h3>
            <p>Total Voyages</p>
          </div>
          <div className="card" style={{ textAlign: 'center' }}>
            <h3 style={{ color: '#28a745' }}>{analytics.summary.active_voyages}</h3>
            <p>Active Voyages</p>
          </div>
          <div className="card" style={{ textAlign: 'center' }}>
            <h3 style={{ color: '#17a2b8' }}>{analytics.summary.completed_voyages}</h3>
            <p>Completed Voyages</p>
          </div>
        </div>
      )}

      {/* Charts */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '30px' }}>
        
        {/* Vessel Type Statistics */}
        {analytics?.vessel_statistics && analytics.vessel_statistics.length > 0 && (
          <div className="card">
            <h3>Voyages by Vessel Type</h3>
            <BarChart width={400} height={300} data={analytics.vessel_statistics}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="vessel__vessel_type" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="count" fill="#8884d8" />
            </BarChart>
          </div>
        )}

        {/* Average Distance by Vessel Type */}
        {analytics?.vessel_statistics && analytics.vessel_statistics.length > 0 && (
          <div className="card">
            <h3>Average Distance by Vessel Type</h3>
            <BarChart width={400} height={300} data={analytics.vessel_statistics.filter(item => item.avg_distance)}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="vessel__vessel_type" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="avg_distance" fill="#82ca9d" />
            </BarChart>
          </div>
        )}

        {/* Voyage Status Distribution */}
        {voyages.length > 0 && (
          <div className="card">
            <h3>Voyage Status Distribution</h3>
            <PieChart width={400} height={300}>
              <Pie
                data={voyages.reduce((acc, voyage) => {
                  const existing = acc.find(item => item.name === voyage.status);
                  if (existing) {
                    existing.value += 1;
                  } else {
                    acc.push({ name: voyage.status, value: 1 });
                  }
                  return acc;
                }, [])}
                cx={200}
                cy={150}
                labelLine={false}
                label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                outerRadius={80}
                fill="#8884d8"
                dataKey="value"
              >
                {voyages.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </div>
        )}
      </div>

      {/* Recent Events */}
      {analytics?.recent_events && analytics.recent_events.length > 0 && (
        <div className="card" style={{ marginTop: '30px' }}>
          <h3>Recent Voyage Events</h3>
          <div style={{ maxHeight: '400px', overflowY: 'auto' }}>
            <div style={{ display: 'grid', gap: '10px' }}>
              {analytics.recent_events.map((event, index) => (
                <div
                  key={index}
                  style={{
                    padding: '15px',
                    border: '1px solid #ddd',
                    borderRadius: '5px',
                    display: 'grid',
                    gridTemplateColumns: '1fr auto',
                    alignItems: 'center',
                  }}
                >
                  <div>
                    <h4>{event.event_type.replace('_', ' ').toUpperCase()}</h4>
                    <p>{event.description}</p>
                    <p>
                      <strong>Location:</strong> {event.latitude.toFixed(4)}, {event.longitude.toFixed(4)}
                    </p>
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <small>{new Date(event.timestamp).toLocaleString()}</small>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Voyage History */}
      <div className="card" style={{ marginTop: '30px' }}>
        <h3>Voyage History</h3>
        <div style={{ marginBottom: '20px' }}>
          <label>Filter by Vessel ID:</label>
          <input
            type="text"
            className="form-control"
            style={{ maxWidth: '200px', display: 'inline-block', marginLeft: '10px' }}
            placeholder="Enter vessel ID"
            value={selectedVessel}
            onChange={(e) => setSelectedVessel(e.target.value)}
          />
        </div>
        
        <div style={{ maxHeight: '500px', overflowY: 'auto' }}>
          {voyages.length === 0 ? (
            <p>No voyage data available.</p>
          ) : (
            <div style={{ display: 'grid', gap: '15px' }}>
              {voyages.map((voyage) => (
                <div
                  key={voyage.id}
                  style={{
                    padding: '20px',
                    border: '1px solid #ddd',
                    borderRadius: '8px',
                    backgroundColor: '#f8f9fa',
                  }}
                >
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr auto', alignItems: 'start' }}>
                    <div>
                      <h4>
                        {voyage.vessel?.name || 'Unknown Vessel'} - Voyage #{voyage.id}
                      </h4>
                      <p>
                        <strong>Origin:</strong> {voyage.origin_port?.name || 'Unknown'} →{' '}
                        <strong>Destination:</strong> {voyage.destination_port?.name || 'Unknown'}
                      </p>
                      {voyage.departure_time && (
                        <p><strong>Departure:</strong> {new Date(voyage.departure_time).toLocaleString()}</p>
                      )}
                      {voyage.arrival_time && (
                        <p><strong>Arrival:</strong> {new Date(voyage.arrival_time).toLocaleString()}</p>
                      )}
                      {voyage.distance && (
                        <p><strong>Distance:</strong> {voyage.distance.toFixed(1)} nautical miles</p>
                      )}
                    </div>
                    <div>
                      <span
                        style={{
                          padding: '5px 15px',
                          backgroundColor: voyage.status === 'completed' ? '#28a745' : 
                                         voyage.status === 'in_progress' ? '#007bff' : 
                                         voyage.status === 'cancelled' ? '#dc3545' : '#6c757d',
                          color: 'white',
                          borderRadius: '15px',
                          fontSize: '12px',
                          fontWeight: 'bold',
                        }}
                      >
                        {voyage.status.replace('_', ' ').toUpperCase()}
                      </span>
                    </div>
                  </div>
                  
                  {voyage.events && voyage.events.length > 0 && (
                    <div style={{ marginTop: '15px' }}>
                      <h5>Recent Events:</h5>
                      <div style={{ maxHeight: '150px', overflowY: 'auto' }}>
                        {voyage.events.slice(0, 3).map((event, index) => (
                          <div key={index} style={{ padding: '5px 0', borderBottom: '1px solid #eee' }}>
                            <strong>{event.event_type}:</strong> {event.description}
                            <br />
                            <small>{new Date(event.timestamp).toLocaleString()}</small>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Analytics;
